"""Tests for tools/gen_module.py renderers, pinned to the committed dumps."""
import os
import shutil
import tempfile
import unittest

from engine.gen_module import render_main, render_variables, render_outputs, render_readme, render_test, render_sample, render_versions, generate_module
from engine.tfschema import load_resource

EXPECTED_SEGMENT_GROUP_VARIABLES = '''\
# GENERATED by tools/gen_module.py from schemas/provider/zpa.json — do not edit.
# Regenerate: make generate

variable "items" {
  description = "zpa_segment_group instances, keyed by a stable identifier."
  type = map(object({
    name = string
    description = optional(string)
    enabled = optional(bool)
    microtenant_id = optional(string)
    applications = optional(list(object({
      id = optional(string)
    })))
  }))
}
'''


class RenderVariablesTest(unittest.TestCase):
    def test_segment_group_exact(self):
        rs = load_resource("zpa_segment_group")
        self.assertEqual(
            render_variables("zpa_segment_group", rs), EXPECTED_SEGMENT_GROUP_VARIABLES
        )

    def test_url_categories_properties(self):
        rs = load_resource("zia_url_categories")
        out = render_variables("zia_url_categories", rs)
        self.assertNotIn("category_id", out)   # computed-only excluded
        self.assertNotIn("\n    val ", out)
        self.assertIn("configured_name = optional(string)", out)
        self.assertIn("urls = optional(list(string))", out)
        self.assertIn("scopes = optional(set(object({", out)
        # max_items=1 list block: typed as ONE object, not list(object)
        self.assertIn("url_keyword_counts = optional(object({", out)
        # nested max_items=1 set block inside scopes: also an object
        self.assertIn("scope_entities = optional(object({", out)


EXPECTED_SEGMENT_GROUP_MAIN = '''\
# GENERATED by tools/gen_module.py from schemas/provider/zpa.json — do not edit.
# Regenerate: make generate

resource "zpa_segment_group" "this" {
  for_each = var.items

  name = each.value.name
  description = each.value.description
  enabled = each.value.enabled
  microtenant_id = each.value.microtenant_id

  dynamic "applications" {
    for_each = each.value.applications == null ? [] : each.value.applications
    content {
      id = applications.value.id
    }
  }
}
'''


class RenderMainTest(unittest.TestCase):
    def test_segment_group_exact(self):
        rs = load_resource("zpa_segment_group")
        self.assertEqual(
            render_main("zpa_segment_group", rs), EXPECTED_SEGMENT_GROUP_MAIN
        )

    def test_url_categories_properties(self):
        rs = load_resource("zia_url_categories")
        out = render_main("zia_url_categories", rs)
        self.assertIn('resource "zia_url_categories" "this"', out)
        self.assertIn('dynamic "scopes"', out)
        self.assertIn('dynamic "url_keyword_counts"', out)
        self.assertNotIn("category_id", out)  # computed-only never assigned

    def test_single_mode_block_wraps_in_list(self):
        fake = {
            "block": {
                "attributes": {"name": {"type": "string", "required": True}},
                "block_types": {
                    "settings": {
                        "nesting_mode": "single",
                        "block": {
                            "attributes": {"on": {"type": "bool", "optional": True}}
                        },
                    }
                },
            }
        }
        out = render_main("zia_fake", fake)
        self.assertIn(
            "for_each = each.value.settings == null ? [] : [each.value.settings]", out
        )


class RenderRestTest(unittest.TestCase):
    def test_outputs_exact(self):
        rs = load_resource("zpa_segment_group")
        out = render_outputs("zpa_segment_group", rs)
        self.assertIn('output "items" {', out)
        self.assertIn("value = zpa_segment_group.this", out)
        self.assertIn('output "name_to_id" {', out)
        self.assertIn(
            "value = { for k, v in zpa_segment_group.this : v.name => v.id }", out
        )

    def test_outputs_omits_name_map_without_name(self):
        fake = {"block": {"attributes": {"id": {"type": "string", "computed": True}}}}
        out = render_outputs("zia_fake", fake)
        self.assertNotIn("name_to_id", out)

    def test_outputs_omits_name_map_for_optional_name(self):
        # An optional name can be null at plan time; a null for-expression
        # key fails the plan, so name_to_id requires a REQUIRED name.
        # Real case: zia_cloud_app_control_rule.
        fake = {
            "block": {
                "attributes": {
                    "id": {"type": "string", "computed": True},
                    "name": {"type": "string", "optional": True},
                }
            }
        }
        out = render_outputs("zia_fake", fake)
        self.assertNotIn("name_to_id", out)

    def test_readme_mentions_regeneration(self):
        rs = load_resource("zpa_segment_group")
        out = render_readme("zpa_segment_group", rs)
        self.assertIn("make generate", out)
        self.assertIn("zpa_segment_group", out)

    def test_sample_has_required_attrs_only(self):
        rs = load_resource("zpa_segment_group")
        sample = render_sample("zpa_segment_group", rs)
        self.assertEqual(sample, '{\n  "items": {\n    "example": {\n      "name": "example"\n    }\n  }\n}\n')

    def test_sample_collections_get_example_members(self):
        # required set(string) must sample as ["example"], not [] — an empty
        # collection can hide provider plan-time validation in module tests.
        rs = load_resource("zpa_application_segment")
        sample = render_sample("zpa_application_segment", rs)
        import json as _json
        item = _json.loads(sample)["items"]["example"]
        self.assertEqual(item["domain_names"], ["example"])

    def test_sample_override_wins(self):
        # enum-constrained required attrs need real values (e.g. protocols);
        # the override map's "sample" key supplies them.
        rs = load_resource("zia_url_filtering_rules")
        sample = render_sample(
            "zia_url_filtering_rules", rs, sample_override={"protocols": ["ANY_RULE"]}
        )
        import json as _json
        item = _json.loads(sample)["items"]["example"]
        self.assertEqual(item["protocols"], ["ANY_RULE"])
        self.assertEqual(item["name"], "example")

    def test_headroom_enum_samples_are_overridden(self):
        from engine.transform import load_override
        import json as _json

        activation = render_sample(
            "zia_activation_status",
            load_resource("zia_activation_status"),
            sample_override=load_override("zia_activation_status").get("sample"),
        )
        self.assertEqual(
            _json.loads(activation)["items"]["example"]["status"], "ACTIVE")

        bandwidth = render_sample(
            "zia_bandwidth_control_rule",
            load_resource("zia_bandwidth_control_rule"),
            sample_override=load_override("zia_bandwidth_control_rule").get("sample"),
        )
        self.assertEqual(
            _json.loads(bandwidth)["items"]["example"]["protocols"], ["ANY_RULE"])

